import React, { useState } from 'react';
import {
  ErpListToolbarButton,
  canDirectEditMasterCatalogRow,
} from '@linm-soft/common-components';
import type { UseCatalogListSelectionResult } from '../../hooks/useCatalogListSelection';
import type { UseSharedCatalogResult } from '../../hooks/useSharedCatalog';
import { isSharedCatalogReadOnly } from '../../hooks/useSharedCatalog';
import { masterCatalogDocumentType } from '../../config/documentHistoryClients';
import { CatalogListToolbar } from './CatalogListToolbar';
import { CatalogListSelectionBanner } from './CatalogListSelectionBanner';
import { CatalogListPagination } from './CatalogListPagination';
import { SharedCatalogPageIntegration, sharedCatalogToolbarActions } from './SharedCatalogPageIntegration';
import { CatalogDocumentHistory } from './CatalogDocumentHistory';
import { CatalogRenameCodeModal } from './CatalogRenameCodeModal';
import { CatalogBatchDeleteModal } from './CatalogBatchDeleteModal';
import type { CatalogBatchDeleteMode } from './CatalogBatchDeleteModal';
import type { SharedCatalogProposalFieldDef } from './sharedCatalogProposalFieldRegistry';
import { useCatalogCodeReplaceContext } from './CatalogCodeReplaceContext';
import type { CatalogListToolbarBridge } from './catalogListToolbarBridge';
import { useCatalogListPermissions } from '../../hooks/useCatalogListPermissions';

export type CatalogListMasterRow = {
  id: string;
  code: string;
  name?: string;
  isActive?: boolean;
  isReadOnly?: boolean;
  scope?: string;
};

/** Resolve document id for history API — supports DTOs that only expose `customerId` / `materialId` on list rows. */
export function catalogListMasterDocumentId(row: CatalogListMasterRow): string {
  if (row.id) return row.id;
  const ext = row as CatalogListMasterRow & {
    customerId?: string;
    materialId?: string;
    customerGroupId?: string;
    materialGroupId?: string;
  };
  return ext.customerId ?? ext.materialId ?? ext.customerGroupId ?? ext.materialGroupId ?? '';
}

export interface CatalogListMasterToolbarSectionProps<T extends CatalogListMasterRow> {
  testIdPrefix: string;
  catalogKind?: string;
  shared?: UseSharedCatalogResult | null;
  selection: UseCatalogListSelectionResult<T>;
  totalCount: number;
  selectableOnPage: T[];
  onAdd: () => void;
  onEdit: (row: T) => void;
  onRefresh: () => void;
  onBatchDelete: (mode: CatalogBatchDeleteMode) => Promise<void>;
  documentType?: string;
  proposalFieldDefs?: SharedCatalogProposalFieldDef[];
  showSchemaConfig?: boolean;
  onOpenSchemaConfig?: () => void;
  /** Nút trái toolbar sau Lịch sử / Sửa config — vd. Xuất Excel (cấm đặt trong filter). */
  toolbarExtraLeftActions?: React.ReactNode;
  canAdd?: boolean;
  fetchDeleteImpact?: React.ComponentProps<typeof CatalogBatchDeleteModal>['fetchDeleteImpact'];
  /** Preview (default) — draft + apply · Confirm — execute ngay */
  renameMode?: 'preview' | 'confirm';
  /** Grid row menu — mở Lịch sử / Đổi mã / Xóa qua toolbar modals. */
  toolbarBridgeRef?: React.MutableRefObject<CatalogListToolbarBridge | null>;
}

/** Sticky toolbar + selection banner + history/rename/delete modals — SSOT `DonViTinhPage`. */
export function CatalogListMasterToolbarSection<T extends CatalogListMasterRow>({
  testIdPrefix,
  catalogKind,
  shared,
  selection,
  totalCount,
  selectableOnPage,
  onAdd,
  onEdit,
  onRefresh,
  onBatchDelete,
  documentType,
  proposalFieldDefs,
  showSchemaConfig,
  onOpenSchemaConfig,
  toolbarExtraLeftActions,
  canAdd = true,
  fetchDeleteImpact,
  renameMode = 'preview',
  toolbarBridgeRef,
}: CatalogListMasterToolbarSectionProps<T>): React.ReactElement {
  const codeReplaceCtx = useCatalogCodeReplaceContext();
  const [renameOpen, setRenameOpen] = useState(false);
  const [deleteOpen, setDeleteOpen] = useState(false);
  const [historyOpen, setHistoryOpen] = useState(false);

  const anchor = selection.activeRow;

  React.useEffect(() => {
    if (!toolbarBridgeRef) return;
    toolbarBridgeRef.current = {
      openHistory: () => setHistoryOpen(true),
      openRename: () => setRenameOpen(true),
      openDelete: () => setDeleteOpen(true),
    };
    return () => {
      toolbarBridgeRef.current = null;
    };
  }, [toolbarBridgeRef]);

  const perms = useCatalogListPermissions(catalogKind ?? '', shared?.meta ?? null);
  const anchorReadOnly = anchor ? isSharedCatalogReadOnly(anchor) : false;
  const showToolbarEdit =
    !!anchor && canDirectEditMasterCatalogRow(anchor, perms);
  const showToolbarView = !!anchor && (!perms.canWrite || anchorReadOnly);
  const docType = documentType ?? (catalogKind ? masterCatalogDocumentType(catalogKind) : undefined);

  const sharedActionsNode =
    catalogKind && shared
      ? sharedCatalogToolbarActions(
          testIdPrefix,
          catalogKind,
          shared,
          anchor
            ? {
                code: anchor.code,
                name: anchor.name,
                isActive: anchor.isActive,
                isReadOnly: anchor.isReadOnly,
                scope: anchor.scope,
              }
            : null,
          proposalFieldDefs && proposalFieldDefs.length > 0 ? proposalFieldDefs : undefined,
        )
      : undefined;

  const hasSelectionOnPage = selection.selectionMode === 'all'
    ? selection.selectedCount > 0
    : selection.selectedCount > 0 && selectableOnPage.some(r => selection.isRowChecked(r));

  return (
    <>
      <CatalogListToolbar
        testIdPrefix={testIdPrefix}
        selectedCount={selection.selectedCount}
        canAdd={canAdd && perms.canWrite}
        showEdit={showToolbarEdit}
        showView={showToolbarView}
        canHistory={!!anchor && !!docType}
        canRename={showToolbarEdit && !!catalogKind}
        canDelete={perms.canWrite && hasSelectionOnPage}
        extraLeftActions={
          (showSchemaConfig && onOpenSchemaConfig) || toolbarExtraLeftActions ? (
            <>
              {showSchemaConfig && onOpenSchemaConfig ? (
                <ErpListToolbarButton
                  action="editConfig"
                  variant="secondary"
                  size="sm"
                  data-testid={`${testIdPrefix}-schema-config-btn`}
                  onClick={onOpenSchemaConfig}
                />
              ) : null}
              {toolbarExtraLeftActions}
            </>
          ) : undefined
        }
        sharedActions={sharedActionsNode}
        onAdd={onAdd}
        onEdit={() => anchor && onEdit(anchor)}
        onView={() => anchor && onEdit(anchor)}
        onHistory={() => setHistoryOpen(true)}
        onRefresh={onRefresh}
        onRename={() => setRenameOpen(true)}
        onDelete={() => setDeleteOpen(true)}
      />

      <CatalogListSelectionBanner
        testIdPrefix={testIdPrefix}
        selectedCount={selection.selectedCount}
        totalCount={totalCount}
        selectionMode={selection.selectionMode}
        pageSelectableCount={selectableOnPage.length}
        onSelectAllDatabase={selection.selectAllInDatabase}
        onClear={selection.clearSelection}
      />

      {anchor && docType && (
        <CatalogDocumentHistory
          testIdPrefix={testIdPrefix}
          documentType={docType}
          documentId={catalogListMasterDocumentId(anchor)}
          documentCode={anchor.code}
          variant="inline"
          isOpen={historyOpen}
          onClose={() => setHistoryOpen(false)}
        />
      )}

      {anchor && catalogKind && (
        <CatalogRenameCodeModal
          testIdPrefix={testIdPrefix}
          isOpen={renameOpen}
          onClose={() => setRenameOpen(false)}
          catalogKind={catalogKind}
          oldCode={anchor.code}
          oldName={anchor.name}
          renameMode={renameMode}
          onCompleted={() => {
            codeReplaceCtx?.bumpReload();
            onRefresh();
          }}
        />
      )}

      <CatalogBatchDeleteModal
        testIdPrefix={testIdPrefix}
        isOpen={deleteOpen}
        onClose={() => setDeleteOpen(false)}
        selectedCount={selection.selectedCount}
        catalogKind={catalogKind ?? testIdPrefix}
        fetchDeleteImpact={
          fetchDeleteImpact ??
          (async () => ({
            canRemove: true,
            impact: [],
          }))
        }
        onConfirm={onBatchDelete}
      />
    </>
  );
}

export interface CatalogListMasterListFooterProps {
  testIdPrefix: string;
  catalogKind?: string;
  shared?: UseSharedCatalogResult | null;
  page: number;
  totalCount: number;
  pageSize: number;
  onPageChange: (page: number) => void;
  onPageSizeChange: (size: number) => void;
}

/** Shell footer — pagination (+ shared approval drawer when `catalogKind`). */
export function CatalogListMasterListFooter({
  testIdPrefix,
  catalogKind,
  shared,
  page,
  totalCount,
  pageSize,
  onPageChange,
  onPageSizeChange,
}: CatalogListMasterListFooterProps): React.ReactElement {
  const pagination = (
    <CatalogListPagination
      testIdPrefix={testIdPrefix}
      page={page}
      totalCount={totalCount}
      pageSize={pageSize}
      onPageChange={onPageChange}
      onPageSizeChange={onPageSizeChange}
    />
  );

  if (catalogKind && shared) {
    return (
      <SharedCatalogPageIntegration
        testIdPrefix={testIdPrefix}
        catalogKind={catalogKind}
        shared={shared}
        pagination={pagination}
      />
    );
  }

  return pagination;
}
