import React from 'react';
import { Button, Checkbox } from '@linm-soft/common-components';
import { CatalogCompanyField } from './CatalogCompanyField';
import styles from '../../styles/erpPage.module.css';

export interface CatalogFormFooterProps {
  testIdPrefix: string;
  checked: boolean;
  onActiveChange: (checked: boolean) => void;
  onCancel: () => void;
  onSave: () => void;
  saving?: boolean;
  activeDisabled?: boolean;
  saveDisabled?: boolean;
  /** Slideout `customFooter` — full width bar */
  variant?: 'modal' | 'slideout';
  activeLabel?: string;
  saveTestId?: string;
  /**
   * Company display label from BE response (`item.companyName`).
   * For create form: pass `items[0]?.companyName` as sessionCompanyName.
   * Never call useCompanyLabelMap() — BE joins PlatformCompanies and returns this field.
   */
  companyName?: string;
  /** Omit company row (e.g. DonViCoSoPage admin) */
  hideCompanyField?: boolean;
  /** Optional slot left of Hủy/Lưu (e.g. Lịch sử). */
  historySlot?: React.ReactNode;
}

export const CatalogFormFooter: React.FC<CatalogFormFooterProps> = ({
  testIdPrefix,
  checked,
  onActiveChange,
  onCancel,
  onSave,
  saving = false,
  activeDisabled = false,
  saveDisabled = false,
  variant = 'modal',
  activeLabel = 'Đang sử dụng',
  saveTestId,
  companyName,
  hideCompanyField = false,
  historySlot,
}) => (
  <>
    {!hideCompanyField && (
      <CatalogCompanyField testIdPrefix={testIdPrefix} companyName={companyName} />
    )}
  <div
    className={
      variant === 'slideout'
        ? `${styles.modalFooterBar} ${styles.slideoutFooterBar}`
        : styles.modalFooterBar
    }
    data-testid={variant === 'slideout' ? `${testIdPrefix}-slideout-footer` : undefined}
  >
    <div className={styles.modalFooterActive} data-testid={`${testIdPrefix}-field-isActive`}>
      <Checkbox
        label={activeLabel}
        checked={checked}
        disabled={activeDisabled}
        onChange={e => onActiveChange(e.target.checked)}
      />
    </div>
    <div className={styles.modalActions}>
      {historySlot}
      <Button variant="secondary" onClick={onCancel}>Hủy</Button>
      <Button
        variant="primary"
        onClick={onSave}
        disabled={saving || saveDisabled}
        data-testid={saveTestId ?? `${testIdPrefix}-save-btn`}
      >
        {saving ? 'Đang lưu...' : 'Lưu'}
      </Button>
    </div>
  </div>
  </>
);

export default CatalogFormFooter;
