import React, { createContext, useCallback, useContext, useMemo, useState } from 'react';
import { useCatalogCodeReplacePending } from '../../hooks/useCatalogCodeReplacePending';
import type { CodeReplacePending } from '../../services/master/codeReplace';

type CatalogCodeReplaceContextValue = {
  getForCode: (code: string) => CodeReplacePending | undefined;
  bumpReload: () => void;
  loading: boolean;
};

const CatalogCodeReplaceContext = createContext<CatalogCodeReplaceContextValue | null>(null);

type CatalogCodeReplaceProviderProps = {
  catalogKind?: string;
  children: React.ReactNode;
};

/** Wrap dm/* list page — badge on grid + refresh after rename. */
export function CatalogCodeReplaceProvider({
  catalogKind,
  children,
}: CatalogCodeReplaceProviderProps): React.ReactElement {
  const [reloadKey, setReloadKey] = useState(0);
  const { getForCode, loading } = useCatalogCodeReplacePending(catalogKind, reloadKey);
  const bumpReload = useCallback(() => setReloadKey(k => k + 1), []);
  const value = useMemo(
    () => ({ getForCode, bumpReload, loading }),
    [getForCode, bumpReload, loading],
  );
  return (
    <CatalogCodeReplaceContext.Provider value={value}>
      {children}
    </CatalogCodeReplaceContext.Provider>
  );
}

export function useCatalogCodeReplaceContext(): CatalogCodeReplaceContextValue | null {
  return useContext(CatalogCodeReplaceContext);
}

export function useCatalogCodeReplaceForCode(code: string): CodeReplacePending | undefined {
  const ctx = useCatalogCodeReplaceContext();
  if (!ctx || !code.trim()) return undefined;
  return ctx.getForCode(code);
}
